+          timeoutMs: 5000,
+          clientName: "gateway",
+          mode: "gateway",
+        },
+      },
+      to: "channel:123",
+      message: "hello",
+    });
+
+    expect(mocks.dispatchChannelMessageAction).not.toHaveBeenCalled();
