+      expect.objectContaining({
+        to: "channel:123",
+        content: "hello",
+        dryRun: true,
+        silent: true,
+        gateway: expect.objectContaining({
+          url: "http://127.0.0.1:18789",
+          token: "tok",
+          timeoutMs: 5000,
+        }),
+      }),
+    );
+  });
